const items = $input.all();
const now = new Date();
const d1 = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const d7 = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const posts = items.filter(item => {
  const pa = item.json.published_at ? new Date(item.json.published_at) : null;
  const aa = item.json.analyzed_at && item.json.analyzed_at !== '';
  const hasLi = item.json.linkedin_post_id && !item.json.linkedin_post_id.startsWith('linkedin_error');
  return pa && pa < d1 && pa > d7 && !aa && hasLi;
});
console.log('[Filtro] Posts totais:', items.length, '| Para analisar:', posts.length);
if (posts.length === 0) {
  return [{ json: { no_posts: true, message: 'Nenhum post para analisar hoje.', total_posts: items.length } }];
}
return posts;

const all = $input.all();
const m = { linkedin: null, instagram: null };
all.forEach(item => {
  const d = item.json;
  if (d.elements && Array.isArray(d.elements)) {
    const s = d.elements[0]?.totalShareStatistics || {};
    m.linkedin = { likes: s.likeCount || 0, comments: s.commentCount || 0, shares: s.shareCount || 0, impressions: s.impressionCount || 0, clicks: s.clickCount || 0 };
  } else if (d.data && Array.isArray(d.data)) {
    const metrics = {};
    d.data.forEach(x => { metrics[x.name] = x.values?.[0]?.value ?? x.value ?? 0; });
    m.instagram = { likes: metrics.likes || 0, comments: metrics.comments || 0, shares: metrics.shares || 0, reach: metrics.reach || 0, impressions: metrics.impressions || 0 };
  }
});
if (!m.linkedin)  m.linkedin  = { likes: 0, comments: 0, shares: 0, impressions: 0, clicks: 0 };
if (!m.instagram) m.instagram = { likes: 0, comments: 0, shares: 0, reach: 0, impressions: 0 };
const ti = (m.linkedin.likes * 2) + (m.linkedin.comments * 5) + (m.linkedin.shares * 10) + (m.instagram.likes) + (m.instagram.comments * 3) + (m.instagram.shares * 7);
const tr = Math.max(m.linkedin.impressions + m.instagram.reach, 1);
const es = Math.round((ti / tr) * 10000) / 100;
return [{ json: { linkedin_metrics: m.linkedin, instagram_metrics: m.instagram, engagement_score: es, total_interactions: ti, total_reach: tr, analyzed_at: new Date().toISOString() } }];

