const item = $input.first().json;
let md = {};
try { md = $('Code — Consolidar Métricas').first().json; } catch(e) {}
let a = {};
try {
  const ao = item.output || item.text || JSON.stringify(item);
  const cl = ao.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
  const m = cl.match(/\{[\s\S]*\}/);
  if (m) a = JSON.parse(m[0]);
} catch(e) {
  a = { performance_rating: 'indefinido', score_real: 5, insights: 'Análise indisponível', top_problem: 'N/A', optimized_prompt_instructions: 'Manter estratégia atual', best_posting_time: '09:00', recommended_content_type: 'imagem', hashtag_strategy: 'hashtags do nicho', next_topic_suggestion: 'Tendências do setor' };
}
return [{ json: { ...a, linkedin_metrics: md.linkedin_metrics || {}, instagram_metrics: md.instagram_metrics || {}, engagement_score: md.engagement_score || 0, total_interactions: md.total_interactions || 0, analyzed_at: md.analyzed_at || new Date().toISOString() } }];

